// Common alias for the term that appears in both copies of the original ensures.
// z3 was failing because each run's postcondition mentions
// `self_.get_pagetable_by_pcid(pcid).unwrap().mapping_4k()` as an opaque subterm;
// the two `forall`-style triggers around `dom().contains(va)` / `[va]` never lined up.
let pt = self_.get_pagetable_by_pcid(pcid).unwrap();
let m = pt.mapping_4k();
let in_dom = m.dom().contains(va);

// Re-state both copies of the first ensures clause so the same `in_dom` term
// is the bridge between r1 and r2.
assert(in_dom == r1.is_Some());
assert(in_dom == r2.is_Some());

// First conjunct of det_resolve_pagetable_mapping_equal: Some/None alignment.
assert(r1.is_Some() == r2.is_Some());
assert((r1 is Some) == (r2 is Some));

if r1.is_Some() {
    assert(r2.is_Some());
    // Re-state both copies of the second ensures clause: both project to the
    // same MapEntry stored at `m[va]`.
    assert(m[va] == page_entry_to_map_entry(&r1->Some_0));
    assert(m[va] == page_entry_to_map_entry(&r2->Some_0));
    assert(page_entry_to_map_entry(&r1->Some_0)
        == page_entry_to_map_entry(&r2->Some_0));

    // `spec_page_entry_to_map_entry` is `MapEntry { addr, write, execute_disable }`,
    // so structural equality on MapEntry forces those three PageEntry fields to agree.
    assert(r1->Some_0.addr == r2->Some_0.addr);
    assert(r1->Some_0.perm.write == r2->Some_0.perm.write);
    assert(r1->Some_0.perm.execute_disable == r2->Some_0.perm.execute_disable);
}

// Final goal: the synthetic equal-fn on Option<PageEntry>.
assert(det_resolve_pagetable_mapping_equal(r1, r2));
